import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';

export default function AdminCommunities() {
  const [communities, setCommunities] = useState([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  const fetchCommunities = async () => {
    setLoading(true);
    try {
      const params = statusFilter ? `?status=${statusFilter}` : '';
      const res = await api.get(`/communities/all${params}`);
      setCommunities(res.data.data || []);
    } catch { toast.error('Failed to load communities'); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchCommunities(); }, [statusFilter]);

  const approveCommunity = async (id, name) => {
    try {
      await api.put(`/communities/${id}/approve`);
      toast.success(`${name} approved`);
      fetchCommunities();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  const filteredCommunities = communities.filter(c =>
    c.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.category?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const stats = {
    total: communities.length,
    pending: communities.filter(c => c.status === 'pending').length,
    approved: communities.filter(c => c.status === 'approved').length,
    rejected: communities.filter(c => c.status === 'rejected').length,
  };

  return (
    <div className="page-wrapper">
      <div className="container">
        {/* Enhanced Header */}
        <div style={{
          background: 'linear-gradient(135deg, rgba(15, 25, 35, 0.8) 0%, rgba(10, 18, 26, 0.9) 100%)',
          borderRadius: 'var(--border-radius-lg)',
          padding: '28px 32px',
          marginBottom: '32px',
          border: '1px solid rgba(0, 255, 255, 0.15)',
          position: 'relative',
          overflow: 'hidden',
        }}>
          <div style={{
            position: 'absolute',
            top: -30,
            right: -30,
            width: 150,
            height: 150,
            borderRadius: '50%',
            background: 'radial-gradient(circle, rgba(0, 255, 255, 0.08) 0%, transparent 70%)',
            pointerEvents: 'none',
          }} />
          <div className="flex-between" style={{ position: 'relative', zIndex: 1 }}>
            <div>
              <h1 style={{
                fontFamily: 'var(--font-display)',
                fontSize: '1.8rem',
                marginBottom: '8px',
                letterSpacing: '-0.02em',
              }}>
                COMMUNITY <span className="gradient-text">MANAGEMENT</span>
              </h1>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', flexWrap: 'wrap' }}>
                <div style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '6px',
                  background: 'rgba(0, 255, 255, 0.1)',
                  padding: '4px 12px',
                  borderRadius: '20px',
                  fontSize: '0.85rem',
                  color: 'var(--cyan-accent)',
                }}>
                  <span>🏛️</span>
                  <span>{stats.total} Total Communities</span>
                </div>
                <div style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '6px',
                  fontSize: '0.85rem',
                  color: 'var(--text-muted)',
                }}>
                  <span>⏳</span>
                  <span>{stats.pending} Pending Review</span>
                </div>
              </div>
            </div>
            <Link to="/admin" className="btn btn-outline" style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
              ← Dashboard
            </Link>
          </div>
        </div>

        {/* Stats Grid */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(4, 1fr)',
          gap: '16px',
          marginBottom: '32px',
        }}>
          {[
            { label: 'Total Communities', value: stats.total, icon: '🏛️', color: 'var(--cyan-accent)' },
            { label: 'Pending Approval', value: stats.pending, icon: '⏳', color: 'var(--warning)' },
            { label: 'Active Communities', value: stats.approved, icon: '✓', color: 'var(--success)' },
            { label: 'Rejected', value: stats.rejected, icon: '✗', color: 'var(--error)' },
          ].map((stat, i) => (
            <div key={i} style={{
              background: 'rgba(10, 18, 26, 0.6)',
              backdropFilter: 'blur(10px)',
              borderRadius: '16px',
              padding: '16px 20px',
              border: `1px solid ${stat.color}20`,
              transition: 'all 0.3s ease',
            }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '8px' }}>
                <span style={{ fontSize: '1.8rem' }}>{stat.icon}</span>
                <span style={{ fontSize: '1.6rem', fontWeight: 700, color: stat.color }}>{stat.value}</span>
              </div>
              <div style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>{stat.label}</div>
            </div>
          ))}
        </div>

        {/* Filter Section */}
        <div style={{
          display: 'flex',
          flexWrap: 'wrap',
          alignItems: 'center',
          justifyContent: 'space-between',
          gap: '16px',
          marginBottom: '28px',
        }}>
          {/* Filter Tabs */}
          <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
            {[
              ['', 'All', '📋'],
              ['pending', 'Pending', '⏳'],
              ['approved', 'Approved', '✓'],
              ['rejected', 'Rejected', '✗'],
            ].map(([v, l, icon]) => (
              <button
                key={v}
                onClick={() => setStatusFilter(v)}
                style={{
                  padding: '8px 18px',
                  borderRadius: '40px',
                  border: `1px solid ${statusFilter === v ? 'var(--cyan-accent)' : 'rgba(0, 255, 255, 0.2)'}`,
                  background: statusFilter === v ? 'rgba(0, 255, 255, 0.1)' : 'transparent',
                  color: statusFilter === v ? 'var(--cyan-accent)' : 'var(--text-secondary)',
                  cursor: 'pointer',
                  fontSize: '0.85rem',
                  fontWeight: 500,
                  transition: 'all 0.2s',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '6px',
                }}
                onMouseEnter={(e) => {
                  if (statusFilter !== v) {
                    e.currentTarget.style.borderColor = 'var(--cyan-accent)';
                    e.currentTarget.style.color = 'var(--cyan-accent)';
                  }
                }}
                onMouseLeave={(e) => {
                  if (statusFilter !== v) {
                    e.currentTarget.style.borderColor = 'rgba(0, 255, 255, 0.2)';
                    e.currentTarget.style.color = 'var(--text-secondary)';
                  }
                }}
              >
                <span>{icon}</span> {l}
              </button>
            ))}
          </div>

          {/* Search Bar */}
          <div style={{
            display: 'flex',
            alignItems: 'center',
            background: 'rgba(10, 18, 26, 0.6)',
            borderRadius: '40px',
            padding: '6px 16px',
            border: '1px solid rgba(0, 255, 255, 0.2)',
          }}>
            <span style={{ marginRight: '8px', color: 'var(--text-muted)' }}>🔍</span>
            <input
              type="text"
              placeholder="Search by name or category..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={{
                background: 'transparent',
                border: 'none',
                color: 'var(--text-primary)',
                fontSize: '0.85rem',
                outline: 'none',
                minWidth: '200px',
              }}
            />
            {searchTerm && (
              <button
                onClick={() => setSearchTerm('')}
                style={{
                  background: 'none',
                  border: 'none',
                  color: 'var(--text-muted)',
                  cursor: 'pointer',
                  marginLeft: '8px',
                }}
              >
                ✕
              </button>
            )}
          </div>
        </div>

        {/* Communities Grid */}
        {loading ? (
          <div className="loading-screen"><div className="spinner" /></div>
        ) : filteredCommunities.length === 0 ? (
          <div className="empty-state" style={{
            padding: '60px 20px',
            textAlign: 'center',
            background: 'rgba(10, 18, 26, 0.4)',
            borderRadius: '24px',
            border: '1px solid rgba(0, 255, 255, 0.1)',
          }}>
            <div className="empty-state-icon" style={{ fontSize: '3rem', marginBottom: '16px' }}>🏛️</div>
            <div style={{ fontSize: '1rem', marginBottom: '8px' }}>No communities found</div>
            <div style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>Try adjusting your filters or search term</div>
          </div>
        ) : (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fill, minmax(360px, 1fr))',
            gap: '24px',
          }}>
            {filteredCommunities.map(c => (
              <div key={c._id} style={{
                background: 'rgba(10, 18, 26, 0.5)',
                borderRadius: '20px',
                border: `1px solid ${c.status === 'pending' ? 'rgba(255, 193, 7, 0.2)' : c.status === 'approved' ? 'rgba(0, 255, 0, 0.2)' : 'rgba(255, 0, 0, 0.2)'}`,
                overflow: 'hidden',
                transition: 'all 0.3s ease',
                backdropFilter: 'blur(10px)',
              }} onMouseEnter={(e) => {
                e.currentTarget.style.transform = 'translateY(-4px)';
                e.currentTarget.style.borderColor = `rgba(0, 255, 255, 0.3)`;
              }} onMouseLeave={(e) => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.borderColor = c.status === 'pending' ? 'rgba(255, 193, 7, 0.2)' : c.status === 'approved' ? 'rgba(0, 255, 0, 0.2)' : 'rgba(255, 0, 0, 0.2)';
              }}>
                {/* Status Bar */}
                <div style={{
                  height: '4px',
                  background: c.status === 'pending' ? 'var(--warning)' : c.status === 'approved' ? 'var(--success)' : 'var(--error)',
                }} />

                <div style={{ padding: '20px' }}>
                  {/* Header */}
                  <div style={{ display: 'flex', alignItems: 'flex-start', gap: '16px', marginBottom: '16px' }}>
                    <div style={{
                      width: '56px',
                      height: '56px',
                      borderRadius: '14px',
                      background: `linear-gradient(135deg, ${c.category === 'Technical' ? 'var(--cyan-accent)' : 'var(--purple-light)'}40, transparent)`,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      fontSize: '1.8rem',
                      fontWeight: 600,
                      color: c.category === 'Technical' ? 'var(--cyan-accent)' : 'var(--purple-light)',
                      border: `1px solid ${c.category === 'Technical' ? 'var(--cyan-accent)' : 'var(--purple-light)'}30`,
                    }}>
                      {c.name?.charAt(0).toUpperCase()}
                    </div>
                    <div style={{ flex: 1 }}>
                      <div style={{
                        fontWeight: 700,
                        fontSize: '1rem',
                        marginBottom: '8px',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'space-between',
                        flexWrap: 'wrap',
                        gap: '8px',
                      }}>
                        {c.name}
                        <span className={`badge badge-${c.status}`} style={{ fontSize: '0.7rem' }}>{c.status}</span>
                      </div>
                      <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
                        <span className={`badge badge-${c.category?.toLowerCase()}`} style={{ fontSize: '0.7rem' }}>
                          {c.category}
                        </span>
                      </div>
                    </div>
                  </div>

                  {/* Description */}
                  <p style={{
                    fontSize: '0.8rem',
                    color: 'var(--text-secondary)',
                    lineHeight: 1.6,
                    marginBottom: '16px',
                    display: '-webkit-box',
                    WebkitLineClamp: 3,
                    WebkitBoxOrient: 'vertical',
                    overflow: 'hidden',
                  }}>
                    {c.description || 'No description provided'}
                  </p>

                  {/* Metadata */}
                  <div style={{
                    fontSize: '0.7rem',
                    color: 'var(--text-muted)',
                    marginBottom: '20px',
                    padding: '12px 0',
                    borderTop: '1px solid rgba(255, 255, 255, 0.05)',
                    borderBottom: '1px solid rgba(255, 255, 255, 0.05)',
                  }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '6px' }}>
                      <span>👤</span>
                      <span>Admin: <span style={{ color: 'var(--text-secondary)' }}>{c.admin?.name || 'Unknown'}</span></span>
                    </div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                      <span>📅</span>
                      <span>Created: {new Date(c.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}</span>
                    </div>
                  </div>

                  {/* Actions */}
                  {c.status === 'pending' && (
                    <div style={{ display: 'flex', gap: '12px' }}>
                      <button
                        onClick={() => approveCommunity(c._id, c.name)}
                        style={{
                          flex: 1,
                          padding: '10px',
                          borderRadius: '12px',
                          background: 'rgba(0, 255, 0, 0.1)',
                          border: '1px solid rgba(0, 255, 0, 0.3)',
                          color: 'var(--success)',
                          cursor: 'pointer',
                          fontWeight: 600,
                          fontSize: '0.8rem',
                          transition: 'all 0.2s',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          gap: '6px',
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.background = 'rgba(0, 255, 0, 0.2)';
                          e.currentTarget.style.transform = 'translateY(-1px)';
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.background = 'rgba(0, 255, 0, 0.1)';
                          e.currentTarget.style.transform = 'translateY(0)';
                        }}
                      >
                        ✓ Approve
                      </button>
                      <button
                        onClick={async () => {
                          const reason = prompt('Please provide a reason for rejection:');
                          if (!reason) return;
                          try {
                            await api.put(`/communities/${c._id}/reject`, { reason });
                            toast.success('Community rejected');
                            fetchCommunities();
                          } catch { toast.error('Failed to reject'); }
                        }}
                        style={{
                          flex: 1,
                          padding: '10px',
                          borderRadius: '12px',
                          background: 'rgba(255, 0, 0, 0.1)',
                          border: '1px solid rgba(255, 0, 0, 0.3)',
                          color: 'var(--error)',
                          cursor: 'pointer',
                          fontWeight: 600,
                          fontSize: '0.8rem',
                          transition: 'all 0.2s',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          gap: '6px',
                        }}
                        onMouseEnter={(e) => {
                          e.currentTarget.style.background = 'rgba(255, 0, 0, 0.2)';
                          e.currentTarget.style.transform = 'translateY(-1px)';
                        }}
                        onMouseLeave={(e) => {
                          e.currentTarget.style.background = 'rgba(255, 0, 0, 0.1)';
                          e.currentTarget.style.transform = 'translateY(0)';
                        }}
                      >
                        ✗ Reject
                      </button>
                    </div>
                  )}
                  {c.status === 'approved' && (
                    <Link
                      to={`/clubs/${c._id}`}
                      style={{
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        gap: '8px',
                        padding: '10px',
                        borderRadius: '12px',
                        background: 'rgba(0, 255, 255, 0.05)',
                        border: '1px solid rgba(0, 255, 255, 0.2)',
                        color: 'var(--cyan-accent)',
                        textDecoration: 'none',
                        fontSize: '0.8rem',
                        fontWeight: 500,
                        transition: 'all 0.2s',
                      }}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.background = 'rgba(0, 255, 255, 0.1)';
                        e.currentTarget.style.transform = 'translateY(-1px)';
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.background = 'rgba(0, 255, 255, 0.05)';
                        e.currentTarget.style.transform = 'translateY(0)';
                      }}
                    >
                      👁️ View Public Page →
                    </Link>
                  )}
                  {c.status === 'rejected' && (
                    <div style={{
                      padding: '10px',
                      borderRadius: '12px',
                      background: 'rgba(255, 0, 0, 0.05)',
                      border: '1px solid rgba(255, 0, 0, 0.2)',
                      textAlign: 'center',
                      fontSize: '0.75rem',
                      color: 'var(--error)',
                    }}>
                      ✗ Rejected
                    </div>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
